const upsertChangeApproval = `-- name: UpsertChangeApproval :one

INSERT INTO change_approvals (tenant_id, change_id, voter_id, vote, note)
VALUES ($1, $2, $3, $4, $5)
ON CONFLICT (change_id, voter_id) DO UPDATE
    SET vote = EXCLUDED.vote,
        note = EXCLUDED.note,
        voted_at = now()
RETURNING id, tenant_id, change_id, voter_id, vote, note, voted_at
`

type UpsertChangeApprovalParams struct {
	TenantID uuid.UUID   `json:"tenant_id"`
	ChangeID uuid.UUID   `json:"change_id"`
	VoterID  uuid.UUID   `json:"voter_id"`
	Vote     string      `json:"vote"`
	Note     pgtype.Text `json:"note"`
}

// ---------------------------------------------------------------------------
// CAB approvals (per-voter votes).
// ---------------------------------------------------------------------------
// INSERT … ON CONFLICT UPDATE — voters can change their vote, but each
// voter has at most one row per change. The audit trail is per-voter,
// not per-vote-attempt; if you want a history of vote changes, the
// change_comments timeline is where that lives.
func (q *Queries) UpsertChangeApproval(ctx context.Context, arg UpsertChangeApprovalParams) (ChangeApproval, error) {
	row := q.db.QueryRow(ctx, upsertChangeApproval,
		arg.TenantID,
		arg.ChangeID,
		arg.VoterID,
		arg.Vote,
		arg.Note,
	)
	var i ChangeApproval
	err := row.Scan(
		&i.ID,
		&i.TenantID,
		&i.ChangeID,
		&i.VoterID,
		&i.Vote,
		&i.Note,
		&i.VotedAt,
	)
	return i, err
}
